@Preview(showBackground = true)
@Composable
private fun RecipeCardContentPreview() {
    RecipeCardContent(
        state = PostCardState(
            id = 1,
            authorName = "Alex Morgan",
            authorHandle = "@alexm",
            date = "22 Apr",
            title = "Protein pancakes with berries",
            imageUrl = "https://images.unsplash.com/photo-1515003197210-e0cd71810b5f",
            likes = "1.2K likes",
            time = "25 min",
            calories = "430 kcal",
            views = "8.4K views",
            tags = listOf(
                TagState(id = 1, title = "Breakfast", isHighlighted = true),
                TagState(id = 2, title = "High Protein"),
                TagState(id = 3, title = "Quick")
            )
        ),
        onTagClick = {}
    )
}
